Hi @xiao0720!

Use the [`filterInit` event](http://mottie.github.io/tablesorter/docs/#filterinit) to target the filter cell & add the button. I left the button alignment and styling up to you in [this demo](http://jsfiddle.net/856bzzeL/963/):

```js
$(function() {
  $('table')
    .on('filterInit', function() {
      var c = this.config,
        $button = $('<button type="button">Add Student</button>').on('click', function() {
          alert('open popup');
        })
      c.$filters.eq(0).append($button);
    })
    .tablesorter({
      theme: 'blue',
      widgets: ['zebra', 'filter']
    });
});
```

